/**
 * SkillRegistry
 * Manages skill registration, lookup and loading
 */

import * as fs from 'fs';
import * as path from 'path';
import { SkillDefinition, AutoloadStrategy } from './types.js';
import { SkillMatcher } from './SkillMatcher.js';

export class SkillRegistry {
  private skills: Map<string, SkillDefinition> = new Map();
  private contentCache: Map<string, string> = new Map();

  /**
   * Scan a directory and register all SKILL.md files found
   * @param dirPath Path to the skills directory (e.g., .opencode/skills/)
   * @returns Number of skills registered
   */
  async registerFromDirectory(dirPath: string): Promise<number> {
    let count = 0;

    if (!fs.existsSync(dirPath)) {
      return 0;
    }

    const entries = fs.readdirSync(dirPath, { withFileTypes: true });

    for (const entry of entries) {
      if (entry.isDirectory()) {
        const skillFilePath = path.join(dirPath, entry.name, 'SKILL.md');
        if (fs.existsSync(skillFilePath)) {
          const skill = await this.parseSkillFile(skillFilePath, entry.name);
          if (skill) {
            this.registerSkill(skill);
            count++;
          }
        }
      }
    }

    return count;
  }

  /**
   * Parse a SKILL.md file and extract metadata
   */
  private async parseSkillFile(
    filePath: string,
    dirName: string
  ): Promise<SkillDefinition | null> {
    try {
      const content = fs.readFileSync(filePath, 'utf-8');

      // Extract description from first heading or paragraph
      const descMatch = content.match(/^#\s+(.+)$/m) || content.match(/^>\s*(.+)$/m);
      const description = descMatch ? descMatch[1].trim() : `Skill: ${dirName}`;

      // Determine autoload strategy from directory name
      const autoload = this.determineAutoloadStrategy(dirName);

      // Determine workflow and phase patterns from directory name
      const { workflowPattern, phasePattern } = this.determinePatterns(dirName);

      return {
        name: dirName,
        description,
        filePath,
        workflowPattern,
        phasePattern,
        autoload,
      };
    } catch {
      return null;
    }
  }

  /**
   * Determine autoload strategy from skill name
   */
  private determineAutoloadStrategy(name: string): AutoloadStrategy {
    if (name.startsWith('sf-workflow-')) {
      return 'workflow_match';
    }
    if (name === 'superpowers-engineering-lessons') {
      return 'always';
    }
    if (name === 'superpowers-brainstorming') {
      return 'phase_match';
    }
    if (name.startsWith('superpowers-')) {
      return 'manual';
    }
    return 'manual';
  }

  /**
   * Determine workflow and phase patterns from skill name
   */
  private determinePatterns(
    name: string
  ): { workflowPattern?: string[]; phasePattern?: string[] } {
    if (name.startsWith('sf-workflow-')) {
      // Extract workflow ID from skill name
      const workflowId = name.replace('sf-workflow-', '');
      return { workflowPattern: [workflowId] };
    }
    if (name === 'superpowers-brainstorming') {
      return { phasePattern: ['requirements', 'intake'] };
    }
    if (name === 'superpowers-writing-plans') {
      return { phasePattern: ['tasks'] };
    }
    if (name === 'superpowers-subagent-driven-development') {
      return { phasePattern: ['development'] };
    }
    if (name === 'superpowers-code-review') {
      return { phasePattern: ['review'] };
    }
    if (name === 'superpowers-verification-before-completion') {
      return { phasePattern: ['verification'] };
    }
    if (name === 'superpowers-tdd') {
      return { phasePattern: ['development'] };
    }
    if (name === 'superpowers-systematic-debugging') {
      return { phasePattern: ['development'] };
    }
    return {};
  }

  /**
   * Register a single skill
   */
  registerSkill(skill: SkillDefinition): void {
    this.skills.set(skill.name, skill);
  }

  /**
   * Find skills matching the given workflow + phase
   */
  findSkills(workflowId: string, phase: string): SkillDefinition[] {
    const allSkills = Array.from(this.skills.values());
    return SkillMatcher.filterMatching(allSkills, workflowId, phase);
  }

  /**
   * Load a skill's content (from cache or file system)
   */
  async loadSkill(name: string): Promise<string> {
    const cached = this.contentCache.get(name);
    if (cached) {
      return cached;
    }

    const skill = this.skills.get(name);
    if (!skill) {
      throw new Error(`Skill not found: ${name}`);
    }

    const content = fs.readFileSync(skill.filePath, 'utf-8');
    this.contentCache.set(name, content);
    skill.content = content;

    return content;
  }

  /**
   * Load all skills matching the given workflow + phase
   * Returns a map of skill name → content
   */
  async loadPhaseSkills(
    workflowId: string,
    phase: string
  ): Promise<Map<string, string>> {
    const matching = this.findSkills(workflowId, phase);
    const result = new Map<string, string>();

    for (const skill of matching) {
      const content = await this.loadSkill(skill.name);
      result.set(skill.name, content);
    }

    return result;
  }

  /**
   * Get a registered skill by name
   */
  getSkill(name: string): SkillDefinition | undefined {
    return this.skills.get(name);
  }

  /**
   * List all registered skills
   */
  listSkills(): SkillDefinition[] {
    return Array.from(this.skills.values());
  }

  /**
   * Clear all registered skills and cache
   */
  clear(): void {
    this.skills.clear();
    this.contentCache.clear();
  }

  /**
   * Get the number of registered skills
   */
  get size(): number {
    return this.skills.size;
  }
}
